// ============================================================
// Mapeia campos do Google Forms → payload da API LeadCapture
// Compatível com perguntas em PT-BR e EN
// ============================================================
const body = $input.first().json.body || $input.first().json;

// ── Campos principais ──────────────────────────────────────
const nome = (
  body.nome ||
  body['Nome completo'] ||
  body['Full Name'] ||
  body.name || ''
).trim();

const email = (
  body.email ||
  body['E-mail'] ||
  body['Email'] ||
  body['E-mail address'] || ''
).trim().toLowerCase();

// Número local SEM DDI (o DDI vem separado)
const telefone = String(
  body.telefone ||
  body['WhatsApp'] ||
  body['Telefone'] ||
  body['Número'] ||
  body['Phone'] || ''
).replace(/\D/g, '');

// ── DDI — vem da pergunta dropdown/lista do formulário ──────
// Aceita: "55", "+55", "🇧🇷 +55 Brasil", "Brasil (+55)"
const ddiRaw = String(
  body.ddi ||
  body['DDI'] ||
  body['DDI País'] ||
  body['Código do País'] ||
  body['country_code'] || ''
);
const ddiMatch = ddiRaw.match(/\+?(\d{1,4})/);
const ddi = ddiMatch ? ddiMatch[1] : '55'; // Padrão Brasil

// ── Capital disponível ──────────────────────────────────────
const capital = (
  body.capital ||
  body['Capital disponível'] ||
  body['Capital Disponivel'] ||
  body['Investimento disponível'] || '0'
);

// ── Localização ─────────────────────────────────────────────
const cidade = (body.cidade || body['Cidade'] || body['City'] || '').trim();
const estado = (body.estado || body['Estado'] || body['State'] || '').trim();
const regiao = (body.regiao_interesse || body['Região de interesse'] || '').trim();

// ── IDs obrigatórios (configurar no webhook do n8n) ─────────
const tenant_id = body.tenant_id || $vars.TENANT_ID || '';
const marca_id  = body.marca_id  || $vars.MARCA_ID  || '';

if (!tenant_id || !marca_id) {
  throw new Error('tenant_id e marca_id são obrigatórios. Configure as variáveis no n8n ou envie no payload.');
}

if (!nome || nome.length < 3) throw new Error('Nome inválido: ' + nome);
if (!email.includes('@'))     throw new Error('E-mail inválido: ' + email);
if (!telefone || telefone.length < 8) throw new Error('Telefone inválido: ' + telefone);

return [{
  json: {
    tenant_id,
    marca_id,
    nome,
    email,
    telefone,
    ddi,
    capital,
    cidade,
    estado,
    regiao_interesse: regiao,
    fonte: 'google-forms',
    _debug: { ddiRaw, ddi, telefone, telefoneFinal: ddi + telefone }
  }
}];

const lead = $input.first().json;
console.log(`[GoogleForms] ✅ Lead salvo: ${lead.leadId} | score ${lead.score} | ${(lead.categoria || '').toUpperCase()}`);
return [{ json: { sucesso: true, leadId: lead.leadId, score: lead.score, categoria: lead.categoria } }];

const resposta = $input.first().json;
const erro = resposta.error || JSON.stringify(resposta);
console.error(`[GoogleForms] ❌ Erro ao salvar lead: ${erro}`);
// Re-lança para ativar notificação de erro do n8n
throw new Error(`LeadCapture API erro: ${erro}`);
